create table if not exists zephyr_mcp_tools (
  id varchar(64) primary key,
  user_name varchar(64) not null,
  server_id varchar(64) not null,
  tool_name varchar(128) not null,
  description varchar(512),
  parameters_json text,
  enabled smallint default 1,
  source varchar(16) not null,
  created_at bigint
);
create index if not exists idx_zephyr_mt_server on zephyr_mcp_tools(server_id);
create index if not exists idx_zephyr_mt_user on zephyr_mcp_tools(user_name);
